mapper.select:
SELECT fk.id, fk.user_id, fk.action_item_id, fk.tag, fk.situation_summary, fk.action_text, fk.created_at, (SELECT COUNT(*) FROM forest_reaction fr WHERE fr.forest_knot_id = fk.id) AS reaction_count, (SELECT COUNT(*) FROM forest_scrap fs WHERE fs.forest_knot_id = fk.id) AS scrap_count FROM forest_knot fk
AND fk.tag = #{tag}
AND (fk.situation_summary ILIKE CONCAT('%', #{keyword}, '%') OR fk.action_text ILIKE CONCAT('%', #{keyword}, '%'))
ORDER BY fk.created_at DESC LIMIT #{limit} OFFSET #{offset}
